    Finds the shortest path between two nodes in a weighted graph.
    The graph is represented as a dictionary where keys are nodes and values are lists of tuples.
    Each tuple contains a node and the weight of the edge connecting it to the starting node.
    """
    queue = [(start, 0)]
    visited = set(start)
    while queue:
        current, distance = queue.pop(0)
        if current == end:
            return distance
        for neighbor, weight in graph[current]:
            if neighbor not in visited:
                visited.add(neighbor)
                queue.append((neighbor, distance + weight))
    return float('inf')

